# Powershell script to migrate OpenAI API calls to Groq\n$content = Get-Content -Path "services\openai_service.py" -Raw\n$content = $content -replace "import openai", "import os`nfrom groq import Groq"\n$content = $content -replace "self.client = openai.OpenAI\(api_key=os.getenv\(""OPENAI_API_KEY""\) or os.getenv\(""GROQ_API_KEY""\)\)", "self.client = Groq(api_key=os.getenv(""GROQ_API_KEY""))"\n$content = $content -replace "model=""gpt-4""", "model=""llama-3.3-70b-versatile"""\nSet-Content -Path "services\openai_service.py" -Value $content -Encoding utf8\n
